// Model — dado puro, sem UI:
struct Tarefa: Identifiable, Codable {
    let id: UUID
    var titulo: String
    var concluida: Bool
    var prazo: Date?
}

// ViewModel — lógica de apresentação:
@Observable
class TarefasViewModel {
    var tarefas: [Tarefa] = []
    var carregando = false
    var erro: String?

    // Propriedade derivada — transforma dado para a View:
    var tarefasPendentes: [Tarefa] {
        tarefas.filter { !$0.concluida }
    }

    // Lógica de negócio fora da View:
    func carregarTarefas() async {
        carregando = true
        defer { carregando = false }
        do {
            tarefas = try await TarefaService.buscarTodas()
        } catch {
            self.erro = error.localizedDescription
        }
    }
}

// View — só layout:
struct TarefasView: View {
    @State private var vm = TarefasViewModel()

    var body: some View {
        List(vm.tarefasPendentes) { tarefa in
            Text(tarefa.titulo)
        }
        .task { await vm.carregarTarefas() }
    }
}

// ALTO ACOPLAMENTO — View conhece URLSession:
class TarefasViewModel {
    func carregar() async throws -> [Tarefa] {
        let (data, _) = try await URLSession.shared.data(from: URL(string: "https://api.app.com/tarefas")!)
        return try JSONDecoder().decode([Tarefa].self, from: data)
    }
}

// BAIXO ACOPLAMENTO — depende de protocolo:
protocol TarefaRepositorio {
    func buscarTodas() async throws -> [Tarefa]
}

// Implementação real para produção:
struct TarefaAPI: TarefaRepositorio {
    func buscarTodas() async throws -> [Tarefa] {
        let (data, _) = try await URLSession.shared.data(from: URL(string: "https://api.app.com/tarefas")!)
        return try JSONDecoder().decode([Tarefa].self, from: data)
    }
}

// Implementação falsa para testes:
struct TarefaFake: TarefaRepositorio {
    func buscarTodas() async throws -> [Tarefa] {
        return [Tarefa(id: UUID(), titulo: "Fake", concluida: false)]
    }
}

// ViewModel usa o protocolo:
@Observable
class TarefasViewModel {
    private let repositorio: TarefaRepositorio

    init(repositorio: TarefaRepositorio = TarefaAPI()) {
        self.repositorio = repositorio
    }
}

